import{_ as a,c as e,o as i,ag as o}from"./chunks/framework.DPDPlp3K.js";const u=JSON.parse('{"title":"共同開発の基本","description":"","frontmatter":{},"headers":[],"relativePath":"text/chapter-2/team-development.md","filePath":"text/chapter-2/team-development.md"}'),r={name:"text/chapter-2/team-development.md"};function s(p,t,n,l,g,c){return i(),e("div",null,t[0]||(t[0]=[o('<h1 id="共同開発の基本" tabindex="-1">共同開発の基本 <a class="header-anchor" href="#共同開発の基本" aria-label="Permalink to &quot;共同開発の基本&quot;">​</a></h1><p>GitHub Flow に従った共同開発の現場において、個人の作業は以下の繰り返しです。</p><ol><li><strong>main からブランチを生やす</strong></li><li><strong>ブランチ内でコミットをしていく</strong></li><li><strong>変更が済んだらプルリクエストを立てる</strong></li><li><strong>main にマージする</strong></li></ol><p>ここまでの操作で全て体験できましたね。この章ではそれぞれの操作の意味を明確にします。</p><h2 id="プルリクエスト" tabindex="-1">プルリクエスト <a class="header-anchor" href="#プルリクエスト" aria-label="Permalink to &quot;プルリクエスト&quot;">​</a></h2><p><strong>プルリクエスト</strong>（Pull Request, PR）という機能はバージョン管理ツールとしての Git 自体には存在せず、GitHub や Gitea などのホスティングサービスの側が提供しています。変更を直接 main にマージするのではなく、変更点に問題がなさそうか、みんなの審判を問うためのワンクッションです。</p><div class="warning custom-block"><p class="custom-block-title">プルリクエストは「プルのリクエスト」ではない</p><p>プルリクエストの趣旨は「このブランチを main に <strong>マージ</strong> してほしい」であって、その先の「このブランチがマージされたら各自で main を <strong>プル</strong> してほしい」ではありません。歴史的経緯から「プルリクエスト」という名前で今まで通ってきたものの、ややこしいという指摘は未だに受け続けているようです。GitHub や Gitea では「プルリクエスト」と呼ばれていますが、他の著名なホスティングサービスの一つである GitLab では「マージリクエスト」というより直感的な表現が使われています。</p></div><p>マージという言葉には前編で説明した以上の意味があることがお分かりになるかと思います。一般に「<strong>ブランチの変更内容同士を統合すること</strong>」をマージと呼びます。</p><p>「sub → main のマージ」とは main ブランチから sub ブランチを生やして以降の main と sub それぞれの変更を統合して main に反映させることを意味します。ところが、前章までの実習では sub ブランチをマージするまでの間 main ブランチに何も変更を加えていないので、マージによって main に sub の変更がそのまま反映されたのです。</p><div class="warning custom-block"><p class="custom-block-title">マージ元はマージの影響を受けない</p><p>sub の変更を main にマージした直後でも sub と main が全く同じ状態になるとは限らないことに注意が必要です。マージされるのは「状態」ではなく「<strong>変更</strong>」なので、sub ブランチの中で変更された箇所以外の sub ブランチの内容は main には影響を与えません。</p><p><img src="https://md.trap.jp/uploads/upload_8b27e59a114f984bf7c41d456dc95b40.png" alt=""></p><p style="font-size:12px;text-align:center;margin:-8px 0 0 0;">sub をマージしてもファイル A の状態が戻るわけではない</p></div><p>ブランチが途中で生えたりマージされたりするとコミットグラフはこんな感じになります。</p><p><img src="https://md.trap.jp/uploads/upload_8354df7754459cfd08b0e67b333e8b19.png" alt=""></p><div class="tip custom-block"><p class="custom-block-title">ブランチという命名について</p><p>そもそも、ほとんどの場合「あとで main にマージする」ために生やすものを「木の枝（ブランチ）」と呼ぶのもちょっと変な話ではありますね。上の図のようにブランチがマージしてしまったら、コミットグラフは少なくともグラフ理論における「木」の定義には当てはまらないものになります。とはいえ、代案を考えろと言われても…。</p></div><h2 id="gitea-の機能" tabindex="-1">Gitea の機能 <a class="header-anchor" href="#gitea-の機能" aria-label="Permalink to &quot;Gitea の機能&quot;">​</a></h2><p>Gitea など多くのホスティングサービスは共同開発の効率化のために様々な機能を提供しています。これらはプルリクエストと同じく Git には存在しない機能です。</p><ul><li><p><strong>Issue</strong> ... Gitea や GitHub では、そのプロダクトについて「現状の問題点」とか「やるべきこと」をメモ・共有するために Issue を立てる機能があります。Issue にはその問題点の性質を示すタグをつけることができます。<a href="https://github.com/traPtitech/traQ_S-UI/issues" target="_blank" rel="noreferrer">traQ フロントエンドリポジトリ の Issues</a> を見るとこの機能の意義が掴めると思います。</p></li><li><p><strong>レビュー</strong> ... 立てられたプルリクエストにおける変更に問題がなさそうかを検証することです。Gitea 上でもレビューをするための UI や機能が提供されていて、1 人以上の Approve がなければプルリクエストのマージができないような設定にすることもできます。</p></li></ul><h2 id="gitignore" tabindex="-1">.gitignore <a class="header-anchor" href="#gitignore" aria-label="Permalink to &quot;.gitignore&quot;">​</a></h2><p>.gitignore は「<strong>作業ディレクトリに載ってはいるが Git リポジトリに含めたくない</strong>」ファイルやディレクトリのパスや拡張子を記しておけるファイルです。多くの場合 .gitignore ファイルはリポジトリのルートに一つだけ置かれ、その中にパスが記されたファイルやディレクトリは Git によるバーション管理を外れます。</p><p>.gitignore は主に以下のような用途で用いられます。</p><h3 id="環境変数の除外" tabindex="-1">環境変数の除外 <a class="header-anchor" href="#環境変数の除外" aria-label="Permalink to &quot;環境変数の除外&quot;">​</a></h3><p>開発したシステムをずっと動かしておきたい場合、自分の PC で動かしておくわけにもいかないので、<a href="https://ns.trap.jp" target="_blank" rel="noreferrer">NeoShowcase</a> などの外部の環境に <strong>デプロイ</strong>（移設）することになります。システムに対し環境ごとに異なる値を与えたい場合、それらは <strong>環境変数</strong> として与えます。NeoShowcase にも登録したアプリケーションそれぞれに環境変数を設定できる UI が存在します。</p><p><img src="https://md.trap.jp/uploads/upload_37df31b5612b2a7c87af06a9658a780f.png" alt=""></p><p>開発中のシステムが参照する環境変数は作業ディレクトリの内部に .env のようなファイルを用意して書いておくと便利です。その上で、本番環境に予め設定してある環境変数と競合を生じないよう、.gitignore に .env を加えてリポジトリからは除外しておく運用が一般的です。</p><div class="info custom-block"><p class="custom-block-title">環境変数と機密情報の秘匿</p><p>traP Gitea 上のリポジトリは部員に対してのみ公開されますが、GitHub などのホスティングサービスを使う場合は Web 上に公開された Git リポジトリで開発を進めていくことも珍しくありません。それどころか、GitHub の無料会員は数年前までプライベートリポジトリを作ることが出来ませんでした。</p><p>実行中のシステムが必要とする情報のうち、API トークン（パスワード）など外部に悪用されないように秘匿しておきたい文字列もよく環境変数として扱われます。実際に環境に依存するか否かはさておき、.gitignore の恩恵でリポジトリに含まれなくなった .env はこうした機密情報を置いておくにはうってつけの場所です。</p></div><h3 id="ライブラリやモジュールの除外" tabindex="-1">ライブラリやモジュールの除外 <a class="header-anchor" href="#ライブラリやモジュールの除外" aria-label="Permalink to &quot;ライブラリやモジュールの除外&quot;">​</a></h3><p>多くのフレームワークでは Web 上からパッケージをインポートしてシステムに組み込むことが一般的です。そのため、パッケージのインポートと管理を担うパッケージマネージャと呼ばれるソフトウェアがフレームワークごとに提供されています。ちなみに、パッケージマネージャは Git 同様に代表的な CLI ソフトウェアの一種です。</p><p>必要なパッケージを箇条書きで記したファイル（依存関係リストファイル）だけあれば、パッケージマネージャがそれを自動で読み取ってパッケージをインポートしてくれるので、パッケージの実体は Git リポジトリに載せておく必要がありません。これらを収めるディレクトリがリポジトリ内に作られる場合、パスを .gitignore に載せておくことで Git リポジトリを軽量化することができます。</p><h3 id="その他の不要なファイルの除外" tabindex="-1">その他の不要なファイルの除外 <a class="header-anchor" href="#その他の不要なファイルの除外" aria-label="Permalink to &quot;その他の不要なファイルの除外&quot;">​</a></h3><p>Git リポジトリを開発に用いる場合、基本的に「<strong>必要最低限のファイルを載せる</strong>」のがよい使い方であるとされています。モジュールだけでなく、ビルドの中間ファイルや生成物など、リポジトリから復元可能なデータや一時的にしか使わないデータの形式や保存場所は .gitignore に追加してリポジトリに含めない工夫がなされることが一般的です。</p><div class="tip custom-block"><p class="custom-block-title">.gitignore の実例とテンプレート</p><p>traQ フロントエンドリポジトリのルートに置かれている <a href="https://github.com/traPtitech/traQ_S-UI/blob/master/.gitignore" target="_blank" rel="noreferrer">.gitignore ファイル</a> を例として見てみます。</p><p><img src="https://md.trap.jp/uploads/upload_c6f36e1ffb29011a1916357da80e14fb.png" alt=""></p><p>実は、写っている最初の 6 行にこれまでに挙げた 3 つの .gitignore の用途が全て含まれています。Vite フレームワークによる Web 開発の実例として専門用語を交えて軽く紹介しますが、あまり深入りせず「そういうもの」程度に読んでいただければ大丈夫です。</p><ul><li><p>6 行目の <code>.env.local</code> は <strong>環境変数を書いておくファイル</strong> です。先ほど「.env は一般に Git リポジトリに含めない」と書きましたが、紛らわしくも運用によっては .env が『環境に依存しない定数』を書く場所として用いられリポジトリに含まれることがあるので、本来の .env の役割である『環境依存』というニュアンスを強めてこのようなファイル名が用いられたりします。</p></li><li><p>2 行目 の <code>node_modules</code> は <strong>モジュールがインポートされるディレクトリ</strong> です。リポジトリのルートに見つかる package.json というファイルに必要なモジュールが全て列挙されているので、npm というパッケージマネージャがあれば自動でこのディレクトリの中身を再現できます。</p></li><li><p>3 行目の <code>/dist</code> は <strong>ビルド成果物を保存するディレクトリ</strong> です。<a href="/text/chapter-2/repository.html#共同開発とブランチ">リポジトリ</a> の章で「フロントエンドは HTML + CSS + JavaScript で出来ている」ことに軽く触れましたが、ビルドされた HTML + CSS + JavaScript のシステムが収められる場所がこの dist です。</p></li></ul><p>リポジトリの作成時に Gitea 側で .gitignore のテンプレートを含めるよう設定することもできます。作りたいシステムで使用するフレームワークごとに豊富なテンプレートが用意されています。</p><p><img src="https://md.trap.jp/uploads/upload_66b56f43c0a0b3abfc352d07ece19a68.png" alt=""></p></div>',30)]))}const m=a(r,[["render",s]]);export{u as __pageData,m as default};
